    id: number
    name?: string
    system_prompt?: string
    dimension?: string
    report_range?: string
    send_cycle?: string
    send_time?: string
}): Promise<void> {
    try {
        await axiosPostWithInt(BASE + 'daily-report/ai-email/task/update', handlerParams(params))
    } catch (e) {
        Message.error(e?.error_msg)
    }
}

async function deleteEmailTask(id: number): Promise<void> {
    try {
        await axiosPostWithInt(BASE + 'daily-report/ai-email/task/delete', handlerParams({ id }))
    } catch (e) {
        Message.error(e?.error_msg)
    }
}

async function toggleEmailTask(id: number, isOn: number): Promise<void> {
    try {
        await axiosPostWithInt(BASE + 'daily-report/ai-email/task/toggle', handlerParams({ id, is_on: isOn }))
    } catch (e) {
        Message.error(e?.error_msg)
    }
}
