Create this file. It's a dialog with left-right layout: left side has task list, right side has config form.

```vue
<template>
    <el-dialog
        title="智能日报邮件"
        :visible="visible"
        :close-on-click-modal="false"
        width="900px"
        top="5vh"
        :append-to-body="true"
        @close="$emit('update:visible', false)"
    >
        <div class="ai-email-config">
            <div class="left-panel">
                <div class="panel-header">任务列表</div>
                <div class="task-list">
                    <div
                        v-for="task in taskList"
                        :key="task.id"
                        :class="['task-item', { active: selectedTask && selectedTask.id === task.id }]"
                        @click="selectTask(task)"
                    >
                        <div class="task-name">{{ task.name }}</div>
                        <div class="task-meta">
                            {{ getCycleLabel(task.send_cycle) }} {{ task.send_time }}
                            <el-switch
                                :value="task.is_on === 1"
                                size="mini"
                                style="margin-left: 8px"
                                @click.native.stop
                                @change="val => handleToggle(task, val)"
                            />
                        </div>
                    </div>
                </div>
                <el-button class="add-btn" type="primary" size="small" icon="el-icon-plus" @click="createTask">
                    添加新任务
                </el-button>
            </div>

            <div class="right-panel" v-if="selectedTask">
                <h3>配置详情</h3>

                <el-form label-position="top" :model="form" v-loading="saving" size="small">
                    <el-row :gutter="16">
                        <el-col :span="12">
                            <el-form-item label="任务名称">
                                <el-input v-model="form.name" placeholder="如：部门日报数据汇总" />
                            </el-form-item>
                        </el-col>
                        <el-col :span="12">
                            <el-form-item label="统计维度">
                                <el-select v-model="form.dimension" style="width:100%">
                                    <el-option value="department" label="按部门" />
                                </el-select>
                            </el-form-item>
                        </el-col>
                    </el-row>

                    <el-row :gutter="16">
                        <el-col :span="8">
                            <el-form-item label="日报范围">
                                <el-select v-model="form.report_range" style="width:100%">
                                    <el-option value="today" label="今日日报" />
                                    <el-option value="yesterday" label="昨日日报" />
                                </el-select>
                            </el-form-item>
                        </el-col>
                        <el-col :span="8">
                            <el-form-item label="发送周期">
                                <el-select v-model="form.send_cycle" style="width:100%">
                                    <el-option value="daily" label="每日" />
                                    <el-option value="weekly_monday" label="每周周一" />
                                    <el-option value="weekly_friday" label="每周周五" />
                                    <el-option value="monthly_first" label="每月1号" />
                                </el-select>
                            </el-form-item>
                        </el-col>
                        <el-col :span="8">
                            <el-form-item label="发送时间">
