                <p>请从左侧选择或创建一个任务</p>
            </div>
        </div>
    </el-dialog>
</template>

<script lang="ts">
import { Vue, Component, Prop, Watch } from 'vue-property-decorator'
import { Message, MessageBox } from 'element-ui'
import { dailyReportAiApis } from '@/apis'
import type { AiEmailTask } from '@/apis/StaffPage/dailyReportAiApis'

@Component({ name: 'AiEmailTaskConfig' })
export default class AiEmailTaskConfig extends Vue {
    @Prop({ type: Boolean, default: false }) visible!: boolean

    taskList: AiEmailTask[] = []
    selectedTask: AiEmailTask | null = null
    saving = false

    form = {
        name: '',
        dimension: 'department',
        report_range: 'today',
        send_cycle: 'daily',
        send_time: '09:00',
        system_prompt: '',
    }

    @Watch('visible')
    onVisibleChange(val: boolean) {
        if (val) {
            this.loadTasks()
        }
    }

    async loadTasks() {
        this.taskList = await dailyReportAiApis.getEmailTaskList()
        // 如果当前选中的任务还在列表中，刷新它
        if (this.selectedTask) {
            const found = this.taskList.find(t => t.id === this.selectedTask!.id)
            if (found) {
                this.selectTask(found)
            } else {
                this.selectedTask = null
            }
        }
    }

    selectTask(task: AiEmailTask) {
        this.selectedTask = task
        this.form = {
            name: task.name,
            dimension: task.dimension,
            report_range: task.report_range,
            send_cycle: task.send_cycle,
            send_time: task.send_time,
            system_prompt: task.system_prompt,
        }
    }

    async createTask() {
        const id = await dailyReportAiApis.createEmailTask({
            name: '新任务',
            system_prompt: '',
            dimension: 'department',
            report_range: 'today',
            send_cycle: 'daily',
            send_time: '09:00',
        })
        if (id) {
            await this.loadTasks()
            const created = this.taskList.find(t => t.id === id)
            if (created) this.selectTask(created)
            Message.success('创建成功')
        }
    }

    async saveTask() {
        if (!this.selectedTask) return
        if (!this.form.name.trim()) {
            Message.warning('请输入任务名称')
            return
        }
        this.saving = true
        try {
            await dailyReportAiApis.updateEmailTask({
                id: this.selectedTask.id,
                ...this.form,
            })
            Message.success('保存成功')
            await this.loadTasks()
        } finally {
            this.saving = false
        }
    }

    async handleDelete() {
        if (!this.selectedTask) return
        try {
            await MessageBox.confirm('确定删除该任务？', '提示', { type: 'warning' })
        } catch {
            return
        }
        await dailyReportAiApis.deleteEmailTask(this.selectedTask.id)
        this.selectedTask = null
        Message.success('已删除')
        await this.loadTasks()
    }

    async handleToggle(task: AiEmailTask, val: boolean) {
        await dailyReportAiApis.toggleEmailTask(task.id, val ? 1 : 0)
        await this.loadTasks()
    }

    getCycleLabel(cycle: string): string {
        const map: Record<string, string> = {
            daily: '每日',
            weekly_monday: '每周周一',
            weekly_friday: '每周周五',
            monthly_first: '每月1号',
        }
        return map[cycle] || cycle
    }
}
</script>

<style lang="less" scoped>
.ai-email-config {
    display: flex;
    min-height: 500px;
    gap: 16px;
}
.left-panel {
    width: 240px;
    flex-shrink: 0;
    border-right: 1px solid #ebeef5;
    padding-right: 16px;
    display: flex;
    flex-direction: column;
}
.panel-header {
    font-weight: bold;
    margin-bottom: 12px;
    font-size: 14px;
}
.task-list {
    flex: 1;
    overflow-y: auto;
}
.task-item {
    padding: 10px 12px;
    border-radius: 4px;
    cursor: pointer;
    margin-bottom: 4px;
    transition: background 0.2s;
    &:hover {
        background: #f5f7fa;
    }
    &.active {
        background: #ecf5ff;
        border-left: 3px solid #409eff;
    }
}
.task-name {
    font-size: 14px;
    font-weight: 500;
    margin-bottom: 4px;
}
.task-meta {
    font-size: 12px;
    color: #909399;
    display: flex;
    align-items: center;
}
.add-btn {
    margin-top: 12px;
    width: 100%;
}
.right-panel {
    flex: 1;
    min-width: 0;
    &.empty {
        display: flex;
        align-items: center;
        justify-content: center;
        color: #909399;
    }
    h3 {
        margin: 0 0 16px;
        font-size: 16px;
    }
}
</style>
```

